3_real_world_example.code:
// --- db.js (ES Module) ---
//  OLD WAY: Wrapped in Immediately Invoked Async Function
// let data;
// (async () => { data = await fetch('/api/config'); })();
// export { data }; // Bug: exports 'undefined' instantly!

//  NEW WAY: Top-Level Await
// The export waits for the fetch to finish.
const response = await fetch('/api/config');
export const config = await response.json();

// --- main.js ---
import { config } from './db.js';
// main.js will wait to execute until db.js's top-level await finishes.
console.log(config); // Always valid data!

